from flask import Flask, redirect, url_for
from flask_oidc import OpenIDConnect, UserManager

app = Flask(__name__)
oidc = OpenIDConnect(app, keys='client_secret', issuer_url='issuer_url')
user_manager = UserManager(oidc)

@oidc.protected_resource_callback
def protected_resource_callback():
    if user_manage.current_user is None:
        return redirect(oidc.signin())
    return app.send_static_file('dashboard.html')

@app.route('/login')
def login():
    return redirect(url_for('oidc.login', state=None, nonce='', scope=['openid']))

